class Solution:
    def solveEquation(self, equation: str) -> str:
        left, right = equation.split('=')
        left_coeff, left_const = 0, 0
        right_coeff, right_const = 0, 0
        for i in range(len(left)):
            if left[i].isdigit():
                if i > 0 and left[i-1] == 'x':
                    left_coeff += int(left[:i])
                else:
                    left_const += int(left[:i])
            elif left[i] == 'x':
                left_coeff += 1
        for i in range(len(right)):
            if right[i].isdigit():
                if i > 0 and right[i-1] == 'x':
                    right_coeff += int(right[:i])
                else:
                    right_const += int(right[:i])
            elif right[i] == 'x':
                right_coeff += 1
        if left_coeff == right_coeff:
            if left_const - right_const == 0:
                return 'Infinite solutions'
            else:
                return 'No solution'
        else:
            return 'x=' + str((right_const - left_const) // (left_coeff - right_coeff))
